import React from "react";
import "./FAQs.css";
import SEO from "../SEO";
const FAQs = () => {
    return (
        <>
            <SEO title="Contact Us" />
            <div className="container faqs">
                <h4>
                    What services does your software development company offer?
                </h4>
                <p className="faqs-p">
                    Invisible Routes offers a range of software development
                    services including web development, mobile app development,
                    custom software solutions, UI/UX design, and more. Visit our
                    Services page for a detailed list of our offerings.
                </p>
                <h4>How can I request a quote for my project?</h4>
                <p className="faqs-p">
                    You can request a quote by filling out the contact form on
                    our website or emailing us at [contact email]. Please
                    provide as much detail as possible about your project
                    requirements, and we'll get back to you with a customized
                    quote.
                </p>
                <h4>What is your approach to software development?</h4>
                <p className="faqs-p">
                    At Invisible Routes, we follow an agile development
                    methodology that focuses on iterative development,
                    collaboration, and continuous improvement. We work closely
                    with our clients to understand their needs, prioritize
                    features, and deliver high-quality software solutions on
                    time and within budget.
                </p>
                <h4>Can I see examples of your previous work?</h4>
                <p className="faqs-p">
                    Yes, you can view our portfolio on our website to see
                    examples of projects we've completed for previous clients.
                    We also have case studies available upon request.
                </p>
                <h4>What industries do you specialize in?</h4>
                <p className="faqs-p">
                    While we have experience working across various industries,
                    we specialize in [list specific industries or sectors, e.g.,
                    healthcare, finance, e-commerce]. Our team has deep domain
                    expertise in these areas and can provide tailored solutions
                    to meet your needs.
                </p>
                <h4>Do you offer internship opportunities at your company?</h4>
                <p className="faqs-p">
                    Yes, we offer internship opportunities for students and
                    recent graduates who are passionate about software
                    development and eager to gain real-world experience. Visit
                    our Careers page for information on current internship
                    openings and how to apply.
                </p>
                <h4>
                    {" "}
                    What qualifications do you look for in internship
                    candidates?
                </h4>
                <p className="faqs-p">
                    We look for candidates who are pursuing a degree in computer
                    science, software engineering, or a related field. Strong
                    programming skills, a willingness to learn, and excellent
                    communication skills are also important.
                </p>
                <h4> What can I expect from the internship program?</h4>
                <p className="faqs-p">
                    Our internship program provides hands-on experience working
                    on real projects alongside experienced developers. Interns
                    will have the opportunity to learn new technologies,
                    collaborate with team members, and contribute to meaningful
                    projects that have a direct impact on our clients.
                </p>
                <h4> How long is the internship program?</h4>
                <p className="faqs-p">
                    The duration of the internship program varies depending on
                    the specific role and project. Internships typically range
                    from [duration, e.g., 2 months to 6 months], with the
                    possibility of extension or conversion to a full-time
                    position for exceptional candidates.
                </p>
            </div>
        </>
    );
};

export default FAQs;
